-- 4.1.3 Группа организации процессов финансового мониторинга (привязка по имени узла)
WITH ins AS (
  INSERT INTO t_p61016064_digital_innovation_i.dept_functions (project_id, dept_name, title, category, source_section_code)
  SELECT 1, 'Департамент финансового мониторинга (ДФМ)', v.title, v.category, '4.1.3'
  FROM (VALUES
    ('Разработка и внедрение методик по оценке и пересмотру степени (уровня) риска совершения клиентом Банка подозрительных операций','methodology'),
    ('Подтверждение сведений о статусе выявленных при проведении идентификации клиентов – физических лиц, являющихся публичными должностными лицами','control'),
    ('Подготовка анкет (досье) клиентов – юридических лиц и индивидуальных предпринимателей для предоставления по запросам надзорных органов','operational'),
    ('Контроль за проведением планового обновления анкет (досье) клиентов – юридических лиц и индивидуальных предпринимателей в соответствии с установленными законодательством Российской Федерации сроками (по клиентам Банка)','control'),
    ('Контроль установления выгодоприобретателей в случаях, предусмотренных законодательством Российской Федерации в сфере ПОД/ФТ, а также нормативными актами Банка России, методическими рекомендациями, регламентами и порядками взаимодействия по реализации в Банке ПВК по ПОД/ФТ','control'),
    ('Консультирование работников Банка по вопросам, возникающим при идентификации и изучении клиентов Банка и оценке степени (уровня) риска совершения клиентом подозрительных операций','communication'),
    ('Изучение и анализ действующих в Банке процессов ПОД/ФТ, выявление возможных зон риска, подлежащих устранению и оптимизации в целях качественного выполнения требований законодательства Российской Федерации и нормативных актов Банка России в сфере ПОД/ФТ','analytical'),
    ('Проведение анализа продуктов (услуг) Банка на предмет анализа и присвоения (пересмотра) уровня риска их использования в целях легализации (отмывания) доходов, полученных преступным путём, или финансирования терроризма в соответствии с требованиями законодательства Российской Федерации и нормативных актов Банка России в сфере ПОД/ФТ','analytical'),
    ('Разработка технических заданий по реализации процессов в рамках функционала Подразделения и УФМ СЦ в целях обеспечения соответствия требованиям законодательства Российской Федерации и нормативных актов Банка России в сфере ПОД/ФТ','methodology'),
    ('Проведение тестирования, формирование тест-кейсов и внедрение бизнес-требований по процедурам ПОД/ФТ в рамках функционала Подразделения','operational'),
    ('Разработка и согласование методических, технологических материалов в рамках функционала Подразделения по применению и использованию новых реализованных процедур ПОД/ФТ в Банке','methodology')
  ) AS v(title, category)
  RETURNING id, source_section_code
)
INSERT INTO t_p61016064_digital_innovation_i.function_org_units (function_id, org_unit_id, role, source_ref)
SELECT ins.id, u.id, 'owner', 'polozhenie'
FROM ins JOIN t_p61016064_digital_innovation_i.org_units u
  ON u.project_id = 1 AND u.code = '4.1.3' AND u.is_archived = false;